import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.NIzFHKo_.js";const f=JSON.parse('{"title":"Infrastructure Layout (Node-Local)","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/30_data/10_infrastructure_layout.md","filePath":"10_core/30_data/10_infrastructure_layout.md"}'),o={name:"10_core/30_data/10_infrastructure_layout.md"};function r(i,e,c,l,p,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="infrastructure-layout-node-local" tabindex="-1">Infrastructure Layout (Node-Local) <a class="header-anchor" href="#infrastructure-layout-node-local" aria-label="Permalink to &quot;Infrastructure Layout (Node-Local)&quot;">​</a></h1><p>Infrastructure nodes (e.g., <code>infra.backup_server</code>) must follow a standardized persistent path pattern to ensure reproducibility, backup compatibility, and operational clarity.</p><h2 id="recommended-persistence-pattern" tabindex="-1">Recommended Persistence Pattern <a class="header-anchor" href="#recommended-persistence-pattern" aria-label="Permalink to &quot;Recommended Persistence Pattern&quot;">​</a></h2><p>The following pattern is the approved baseline for local persistence under the <code>C:/QiLabs/</code> root.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/QiLabs/</span></span>
<span class="line"><span>  QiData/</span></span>
<span class="line"><span>    infra/</span></span>
<span class="line"><span>      backup_server/</span></span>
<span class="line"><span>        configs/     # Service-specific configuration files</span></span>
<span class="line"><span>        compose/     # Docker Compose / manifest files</span></span>
<span class="line"><span>        env/         # Access-controlled environment files (NOT in repo)</span></span>
<span class="line"><span>        exports/     # Temporary exports or reports</span></span>
<span class="line"><span>        logs/        # Rotated system and container logs</span></span>
<span class="line"><span>        backups/     # Scheduled local snapshots</span></span>
<span class="line"><span>        restore/     # Workspace for testing restore procedures</span></span>
<span class="line"><span>    services/</span></span>
<span class="line"><span>      postgres/      # Relational storage volumes</span></span>
<span class="line"><span>      vector/        # Vector database indices</span></span>
<span class="line"><span>      automation/    # Flow data and configs (e.g., n8n, Prefect)</span></span>
<span class="line"><span>      ai/            # Model weights and cache</span></span>
<span class="line"><span>      proxy/         # SSL certs and routing configs</span></span></code></pre></div><h2 id="persistence-rules" tabindex="-1">Persistence Rules <a class="header-anchor" href="#persistence-rules" aria-label="Permalink to &quot;Persistence Rules&quot;">​</a></h2><ol><li><strong>Separation of Concerns</strong>: Service configurations must be separable from raw data volumes.</li><li><strong>Backup Accessibility</strong>: Local snapshots in <code>QiData/infra/backups/</code> must be accessible to off-node backup jobs.</li><li><strong>Secret Management</strong>: <code>.env</code> files and secret keys must reside in <code>QiData/infra/env/</code>, be access-controlled at the host level, and be strictly excluded from version control.</li><li><strong>Logging</strong>: Container logs should be directed to <code>QiData/infra/logs/</code> or managed by a host-level rotated logging service.</li><li><strong>Restore Validation</strong>: Every infrastructure node must maintain a <code>restore/</code> directory for periodic verification of data integrity.</li></ol>`,7)])])}const g=a(o,[["render",r]]);export{f as __pageData,g as default};
